	for k, rm := range r.requests {
		if now.Sub(rm.lastSeen) > r.cfg.IdleTTL {
			toUnreg = append(toUnreg, rm.requestCounter, rm.requestDur, rm.inFlight)
			delete(r.requests, k)
		}
	}
	r.activeUsers.Set(float64(len(r.users)))
	r.activeRequests.Set(float64(len(r.requests)))
	r.mu.Unlock()

	for _, c := range toUnreg {
		_ = r.reg.Unregister(c)
	}
